const fs = require('fs');
const path = require('path');

const DATA_FILE = path.join(__dirname, 'data.json');

function readData() {
  if (!fs.existsSync(DATA_FILE)) {
    fs.writeFileSync(DATA_FILE, JSON.stringify([]), 'utf8');
    return [];
  }
  try {
    const content = fs.readFileSync(DATA_FILE, 'utf8');
    return JSON.parse(content);
  } catch (e) {
    return [];
  }
}

function writeData(data) {
  fs.writeFileSync(DATA_FILE, JSON.stringify(data, null, 2), 'utf8');
}

function getAllUrls() {
  return readData();
}

function findByCode(code) {
  const data = readData();
  return data.find(entry => entry.code === code) || null;
}

function findByOriginalUrl(url) {
  const data = readData();
  return data.find(entry => entry.originalUrl === url) || null;
}

function save(entry) {
  const data = readData();
  data.push(entry);
  writeData(data);
  return entry;
}

function incrementClicks(code) {
  const data = readData();
  const index = data.findIndex(entry => entry.code === code);
  if (index !== -1) {
    data[index].clicks = (data[index].clicks || 0) + 1;
    writeData(data);
    return data[index];
  }
  return null;
}

function deleteExpired() {
  const data = readData();
  const now = new Date().toISOString();
  const active = data.filter(entry => {
    if (!entry.expiresAt) return true;
    return entry.expiresAt > now;
  });
  if (active.length !== data.length) {
    writeData(active);
  }
  return data.length - active.length;
}

module.exports = {
  getAllUrls,
  findByCode,
  findByOriginalUrl,
  save,
  incrementClicks,
  deleteExpired,
};

const express = require('express');
const { nanoid } = require('nanoid');
const {
  getAllUrls,
  findByCode,
  findByOriginalUrl,
  save,
} = require('../db');

const router = express.Router();

// POST /api/shorten
router.post('/shorten', (req, res) => {
  const { url, customCode, expiresIn } = req.body;

  if (!url) {
    return res.status(400).json({ success: false, error: 'url is required' });
  }

  // Basic URL validation
  try {
    new URL(url);
  } catch (e) {
    return res.status(400).json({ success: false, error: 'Invalid URL format' });
  }

  let code = customCode;

  if (code) {
    // Check for duplicate custom code
    const existing = findByCode(code);
    if (existing) {
      return res.status(409).json({ success: false, error: 'Custom code already in use' });
    }
  } else {
    // Check if this original URL was already shortened
    const existingByUrl = findByOriginalUrl(url);
    if (existingByUrl) {
      const shortUrl = `${req.protocol}://${req.get('host')}/${existingByUrl.code}`;
      return res.json({
        success: true,
        code: existingByUrl.code,
        shortUrl,
        originalUrl: existingByUrl.originalUrl,
        expiresAt: existingByUrl.expiresAt,
        clicks: existingByUrl.clicks,
      });
    }
    code = nanoid(7);
  }

  const createdAt = new Date().toISOString();
  let expiresAt = null;
  if (expiresIn) {
    const hours = parseFloat(expiresIn);
    if (!isNaN(hours) && hours > 0) {
      expiresAt = new Date(Date.now() + hours * 60 * 60 * 1000).toISOString();
    }
  }

  const entry = {
    code,
    originalUrl: url,
    createdAt,
    expiresAt,
    clicks: 0,
  };

  save(entry);

  const shortUrl = `${req.protocol}://${req.get('host')}/${code}`;

  return res.status(201).json({
    success: true,
    code,
    shortUrl,
    originalUrl: url,
    expiresAt,
    clicks: 0,
  });
});

// GET /api/urls
router.get('/urls', (req, res) => {
  const urls = getAllUrls();

  // Sort by createdAt descending (newest first)
  const sorted = urls.slice().sort((a, b) => {
    return new Date(b.createdAt) - new Date(a.createdAt);
  });

  const result = sorted.map(entry => ({
    ...entry,
    shortUrl: `${req.protocol}://${req.get('host')}/${entry.code}`,
  }));

  return res.json({ success: true, urls: result });
});

// GET /api/stats/:code
router.get('/stats/:code', (req, res) => {
  const { code } = req.params;
  const entry = findByCode(code);

  if (!entry) {
    return res.status(404).json({ success: false, error: 'Code not found' });
  }

  const shortUrl = `${req.protocol}://${req.get('host')}/${entry.code}`;
  const now = new Date().toISOString();
  const isExpired = entry.expiresAt ? entry.expiresAt <= now : false;

  return res.json({
    success: true,
    code: entry.code,
    shortUrl,
    originalUrl: entry.originalUrl,
    createdAt: entry.createdAt,
    expiresAt: entry.expiresAt,
    clicks: entry.clicks,
    isExpired,
  });
});

module.exports = router;

const express = require('express');
const cors = require('cors');
const path = require('path');
const { findByCode, incrementClicks, deleteExpired } = require('./db');

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// API routes
app.use('/api', require('./routes/api'));

// Redirect route: GET /:code
app.get('/:code', (req, res) => {
  const { code } = req.params;

  const entry = findByCode(code);

  if (!entry) {
    return res.status(404).json({ error: 'Short URL not found' });
  }

  // Check expiry
  if (entry.expiresAt && new Date(entry.expiresAt) <= new Date()) {
    return res.status(410).json({ error: 'This short URL has expired' });
  }

  // Increment click count
  incrementClicks(code);

  // 301 redirect to original URL
  return res.redirect(301, entry.originalUrl);
});

// Root route: serve index.html (handled by static middleware, but explicit fallback)
app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

// Start server
app.listen(PORT, () => {
  console.log(`URL Shortener running on port ${PORT}`);

  // Delete expired entries immediately on startup
  const deletedOnStart = deleteExpired();
  if (deletedOnStart > 0) {
    console.log(`Deleted ${deletedOnStart} expired entries on startup`);
  }

  // Run deleteExpired every hour
  setInterval(() => {
    const deleted = deleteExpired();
    if (deleted > 0) {
      console.log(`Deleted ${deleted} expired entries`);
    }
  }, 60 * 60 * 1000);
});

module.exports = app;

